-- ════════════════════════════════════════════════════════════
-- 2026（民國 115）年勞健保級距金額表 — 完整版 82 級
-- 涵蓋 1,500 ~ 313,000，補完前一支 (20260514240000) 缺的 47 級高薪資
--
-- 欄位對應：
--   labor_ins_brackets.employer_premium  = 公司勞保 + 災保（職業災害保險）
--   labor_ins_brackets.employee_premium  = 員工勞保
--   health_ins_brackets.employer_premium = 公司健保
--   health_ins_brackets.employee_premium = 員工健保
--   勞退 6% 由系統 hardcode 計算（級距 × 6%，150,000 上限）
--
-- 法定凍結：
--   勞保 45,800 凍結（員工 1,145、公司勞保 4,008）
--   災保 72,800 凍結 153
--   勞退 150,000 凍結 9,000
--   健保到 313,000 持續上升
--
-- ON CONFLICT (year, grade) → UPDATE，安全覆蓋前一支灌的 35 級
-- ════════════════════════════════════════════════════════════

BEGIN;

-- ═══ 勞保 82 級 ═══
ON CONFLICT (year, grade) DO UPDATE SET
  insured_salary   = EXCLUDED.insured_salary,
  min_salary       = EXCLUDED.min_salary,
  employee_premium = EXCLUDED.employee_premium,
  employer_premium = EXCLUDED.employer_premium;


-- ═══ 健保 82 級 ═══
ON CONFLICT (year, grade) DO UPDATE SET
  insured_salary   = EXCLUDED.insured_salary,
  min_salary       = EXCLUDED.min_salary,
  employee_premium = EXCLUDED.employee_premium,
  employer_premium = EXCLUDED.employer_premium;

COMMIT;

-- 驗證：兩表 2026 各應 82 筆
SELECT 'labor' AS tbl, COUNT(*) AS rows, MAX(insured_salary) AS max_salary
  FROM labor_ins_brackets WHERE year = 2026
UNION ALL
SELECT 'health', COUNT(*), MAX(insured_salary)
  FROM health_ins_brackets WHERE year = 2026;
